    <input id="vulnerableInput" type="text" placeholder="Search...">
    <button onclick="searchVulnerable()">Search</button>
    <pre id="vulnerableResult"></pre>
</div>

<div class="section">
    <h2>Safe Version (Parameterized Queries)</h2>
    <input id="safeInput" type="text" placeholder="Search...">
    <button onclick="searchSafe()">Search</button>
    <pre id="safeResult"></pre>
</div>

<div class="section">
    <h2>Explanation</h2>
    <p>SQL injection occurs when an attacker is able to inject malicious SQL code into a web application's database in order to extract or modify sensitive data.</p>
    <p>In the vulnerable version below, user input is directly concatenated into a SQL query string. This allows an attacker to inject malicious SQL.</p>
    <p>In contrast, the safe version uses parameterized queries. The SQL query is defined with parameters, and then the user input is passed as a parameter to the query. This way, the database driver interprets the input as data, not as part of the SQL code, preventing injection.</p>
</div>

<script>
// Mock product database
const products = [
    { id: 1, name: "Product A", description: "This is product A" },
    { id: 2, name: "Product B", description: "This is product B" },
    { id: 3, name: "Product C", description: "This is product C" }
];

// Vulnerable version using string concatenation
function searchVulnerable() {
    const input = document.getElementById('vulnerableInput').value;
    const resultElement = document.getElementById('vulnerableResult');
    resultElement.innerText = '';

    // Simulating a SQL query with string concatenation
    const vulnerableQuery = `SELECT * FROM products WHERE name LIKE '%${input}%'`;
    console.log('Vulnerable Query:', vulnerableQuery);

    const result = products.filter(product => product.name.toLowerCase().includes(input.toLowerCase()));
    resultElement.innerText = JSON.stringify(result, null, 2);
}

// Safe version using parameterized queries
function searchSafe() {
    const input = document.getElementById('safeInput').value;
    const resultElement = document.getElementById('safeResult');
    resultElement.innerText = '';

    // Simulating a SQL query with parameterized query
    const safeQuery = "SELECT * FROM products WHERE name LIKE ?";
    console.log('Safe Query:', safeQuery);

    // Here, we're simulating passing the input as a parameter
    const result = products.filter(product => product.name.toLowerCase().includes(input.toLowerCase()));
